import java.io.*;import java.util.*;class Main{static class Item{int value,freq,time;Item(int v,int f,int t){value=v;freq=f;time=t;}}static String run(int cap,String[]ops,int[][]args){int clock=0;HashMap<Integer,Item> cache=new HashMap<>();ArrayList<String>res=new ArrayList<>();for(int i=0;i<ops.length;i++){clock++;switch(ops[i]){case "C":cache.clear();res.add("null");break;case "P":int key=args[i][0],val=args[i][1];if(cap==0){res.add("null");break;}if(cache.containsKey(key)){Item it=cache.get(key);cache.put(key,new Item(val,it.freq+1,clock));}else{if(cache.size()==cap){int victim=-1;Item best=null;for(var e:cache.entrySet()){int k=e.getKey();Item it=e.getValue();if(best==null||it.freq<best.freq||it.freq==best.freq&&(it.time<best.time||it.time==best.time&&k<victim)){victim=k;best=it;}}cache.remove(victim);}cache.put(key,new Item(val,1,clock));}res.add("null");break;default:key=args[i][0];if(!cache.containsKey(key))res.add("-1");else{Item it=cache.get(key);cache.put(key,new Item(it.value,it.freq+1,clock));res.add(Integer.toString(it.value));}}}return "["+String.join(",",res)+"]";}public static void main(String[]a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int cap=Integer.parseInt(d[idx++]),m=Integer.parseInt(d[idx++]);String[]ops=new String[m];int[][]args=new int[m][];for(int i=0;i<m;i++){ops[i]=d[idx++];if(ops[i].equals("P"))args[i]=new int[]{Integer.parseInt(d[idx++]),Integer.parseInt(d[idx++])};else if(ops[i].equals("G"))args[i]=new int[]{Integer.parseInt(d[idx++])};else args[i]=new int[]{};}if(tc>0)out.append("\n\n");out.append(run(cap,ops,args));}System.out.print(out);}}
